# --- Data Store (In-memory for simplicity) ---
class User:
    def __init__(self, id, username, email, bio, phone, address):
        self.id = id
        self.username = username
        self.email = email
        self.bio = bio
        self.phone = phone
        self.address = address

class Post:
    def __init__(self, id, title, content, author_id):
        self.id = id
        self.title = title
        self.content = content
        self.author_id = author_id

users_db = {
    "1": User("1", "alice", "alice@example.com", "Software Engineer", "111-222-3333", "123 Main St"),
    "2": User("2", "bob", "bob@example.com", "Product Manager", "444-555-6666", "456 Oak Ave"),
}

posts_db = {
    "101": Post("101", "My First Post", "This is the content of my first post.", "1"),
    "102": Post("102", "GraphQL Basics", "Learning about GraphQL schemas and resolvers.", "1"),
    "103": Post("103", "A New Idea", "Brainstorming some new features.", "2"),
}

# --- Middleware for Authentication ---
class AuthMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        # Simulate authentication:
        # For this example, we'll just set a 'current_user' based on a header.
        # In a real app, this would involve token verification, session lookup, etc.
        auth_header = request.headers.get("X-Auth-User-ID")
        if auth_header and auth_header in users_db:
            request.state.current_user = users_db[auth_header]
        else:
            request.state.current_user = None # No user authenticated

        response = await call_next(request)
        return response

