# --- Resolvers ---
query = QueryType()

@query.field("user")
def resolve_user(_, info, id):
    return users_db.get(id)

@query.field("users")
def resolve_users(_, info):
    return list(users_db.values())

@query.field("post")
def resolve_post(_, info, id):
    return posts_db.get(id)

@query.field("posts")
def resolve_posts(_, info):
    return list(posts_db.values())

@query.field("me")
def resolve_me(_, info):
    # The current_user is set by the AuthMiddleware and available via info.context
    return info.context["request"].state.current_user

# Field resolvers for User type
# These will be called for each field requested on a User object
