def resolve_user_id(obj, info):
    return obj.id

def resolve_user_username(obj, info):
    return obj.username

def resolve_user_bio(obj, info):
    return obj.bio

def resolve_user_email(obj, info):
    return obj.email

def resolve_user_phone(obj, info):
    return obj.phone

def resolve_user_address(obj, info):
    return obj.address

def resolve_user_posts(obj, info):
    # Filter posts by author_id
    return [post for post in posts_db.values() if post.author_id == obj.id]

# Field resolvers for Post type
def resolve_post_id(obj, info):
    return obj.id

def resolve_post_title(obj, info):
    return obj.title

def resolve_post_content(obj, info):
    return obj.content

def resolve_post_author(obj, info):
    return users_db.get(obj.author_id)

